Also update the `MockEventSource` class to track instances for assertion:

```typescript
class MockEventSource {
  static instances: MockEventSource[] = [];
  url: string;
  listeners: Map<string, Array<(event: Event) => void>>;
  readyState: number;

  constructor(url: string) {
    this.url = url;
    this.listeners = new Map();
    this.readyState = 1; // OPEN
    MockEventSource.instances.push(this);
  }

  addEventListener(type: string, listener: (event: Event) => void) {
    if (!this.listeners.has(type)) {
      this.listeners.set(type, []);
    }
    this.listeners.get(type)!.push(listener);
  }

  removeEventListener(type: string, listener: (event: Event) => void) {
    const listeners = this.listeners.get(type);
    if (listeners) {
      const index = listeners.indexOf(listener);
      if (index > -1) {
        listeners.splice(index, 1);
      }
    }
  }

  close() {
    this.readyState = 2; // CLOSED
  }
}
```

Add `MockEventSource.instances = [];` to the `beforeEach` block.

## New Tests

Add a new `describe` block after the existing `'EventSource subscription for real-time sync'` block:

```typescript
describe('data path debug toggles', () => {
  it('does not create EventSource when enableCrossClientSync is false', async () => {
    const { useAppStore } = await vi.importActual<Record<string, unknown>>('@/layers/shared/model');
    // Override the mock state before rendering
    (vi.mocked(useAppStore) as unknown as { setState: (p: Record<string, unknown>) => void }).setState({
      enableCrossClientSync: false,
    });

    const transport = createMockTransport();
    const { result } = renderHook(() => useChatSession('s1'), {
      wrapper: createWrapper(transport),
    });

    await waitFor(() => expect(result.current.status).toBe('idle'));

    // All instances should be closed or none created for the session stream URL
    const streamInstances = MockEventSource.instances.filter((es) =>
      es.url.includes('/api/sessions/s1/stream')
    );
    expect(streamInstances).toHaveLength(0);
  });

  it('creates EventSource when enableCrossClientSync is true (default)', async () => {
    const transport = createMockTransport();
    const { result } = renderHook(() => useChatSession('s1'), {
      wrapper: createWrapper(transport),
    });

    await waitFor(() => expect(result.current.status).toBe('idle'));

    const streamInstances = MockEventSource.instances.filter((es) =>
      es.url.includes('/api/sessions/s1/stream')
    );
    expect(streamInstances.length).toBeGreaterThan(0);
  });
});
```

Note: Testing `enableMessagePolling` at the hook test level is difficult because `refetchInterval` is internal to TanStack Query. The store tests (task 3.1) cover that the toggle persists correctly, and the implementation is a single `if (!enableMessagePolling) return false;` guard that is straightforward to verify by code inspection.

## Acceptance Criteria

- `MockEventSource` tracks instances via a static `instances` array, cleared in `beforeEach`
- The `useAppStore` mock supports overriding `enableCrossClientSync` and `enableMessagePolling`
- Test verifies no EventSource is created when `enableCrossClientSync` is `false`
- Test verifies EventSource IS created when `enableCrossClientSync` is `true`
- All existing tests continue to pass (mock state defaults include `enableCrossClientSync: true` and `enableMessagePolling: true`)
- All tests pass with `pnpm vitest run apps/client/src/layers/features/chat/__tests__/use-chat-session.test.tsx`
